import React, { useState, useEffect, useRef } from 'react';

export default function BurgerMenu({ links = [], onSearch }) {
    const [open, setOpen] = useState(false);
    const [query, setQuery] = useState('');
    const ref = useRef(null);

    useEffect(() => {
        function handleOutside(e) {
            if (ref.current && !ref.current.contains(e.target)) {
                setOpen(false);
            }
        }
        document.addEventListener('mousedown', handleOutside);
        return () => document.removeEventListener('mousedown', handleOutside);
    }, []);

    const buttonStyle = {
        background: 'rgba(255,255,255,0.9)',
        border: 'none',
        padding: 8,
        borderRadius: 6,
        cursor: 'pointer'
    };

    const menuStyle = {
        position: 'absolute',
        top: 'calc(100% + 8px)',
        right: 0,
        background: 'white',
        boxShadow: '0 6px 18px rgba(0,0,0,0.12)',
        borderRadius: 8,
        padding: 12,
        minWidth: 220,
        zIndex: 40
    };

    return (
        <div ref={ref} style={{ position: 'relative', display: 'inline-block' }}>
            <button
                aria-expanded={open}
                aria-label={open ? 'Fermer le menu' : 'Ouvrir le menu'}
                onClick={() => setOpen((s) => !s)}
                style={buttonStyle}
            >
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <rect x="3" y="6" width="18" height="2" rx="1" fill="#333" />
                    <rect x="3" y="11" width="18" height="2" rx="1" fill="#333" />
                    <rect x="3" y="16" width="18" height="2" rx="1" fill="#333" />
                </svg>
            </button>

            {open && (
                <div style={menuStyle} role="menu" aria-label="Menu déroulant">
                    <div style={{ marginBottom: 8 }}>
                        <label htmlFor="menu-search" style={{ display: 'block', fontSize: 12, color: '#666', marginBottom: 6 }}>Rechercher une recette</label>
                        <div style={{ display: 'flex', gap: 6 }}>
                            <input
                                id="menu-search"
                                value={query}
                                onChange={(e) => setQuery(e.target.value)}
                                placeholder="Ex: carbonara"
                                style={{ flex: 1, padding: '6px 8px', border: '1px solid #ddd', borderRadius: 6 }}
                                onKeyDown={(e) => {
                                    if (e.key === 'Enter') {
                                        if (onSearch) onSearch(query);
                                        setOpen(false);
                                    }
                                }}
                            />
                            <button
                                onClick={() => {
                                    if (onSearch) onSearch(query);
                                    setOpen(false);
                                }}
                                style={{ padding: '6px 8px', borderRadius: 6, border: '1px solid #ddd', background: '#f7f7f7', cursor: 'pointer' }}
                            >
                                Go
                            </button>
                        </div>
                    </div>

                    <ul style={{ listStyle: 'none', margin: 0, padding: 0 }}>
                        {links.length > 0 ? (
                            links.map((l, i) => (
                                <li key={i} style={{ marginBottom: i < links.length - 1 ? 8 : 0 }}>
                                    <a href={l.href} onClick={() => setOpen(false)} style={{ color: '#111', textDecoration: 'none' }}>{l.label}</a>
                                </li>
                            ))
                        ) : (
                            <li><a href="#" onClick={() => setOpen(false)} style={{ color: '#111', textDecoration: 'none' }}>Accueil</a></li>
                        )}
                    </ul>
                </div>
            )}
        </div>
    );
}
